class CollaborateCraft:
    """Main application class for the CollaborateCraft platform."""

    def __init__(self):
        self.users: Dict[str, User] = {}
        self.projects: Dict[str, Project] = {}
        self._username_index: Dict[str, str] = {}
        self._email_index: Dict[str, str] = {}

    # --- User Management ---

    def create_user(self, username: str, email: str, name: str = "",
                    bio: str = "", skills: Optional[List[str]] = None,
                    interests: Optional[List[str]] = None) -> User:
        if not User.validate_username(username):
            raise ValueError("Invalid username. Must be alphanumeric and <= 50 chars.")
        if not User.validate_email(email):
            raise ValueError("Invalid email format")
        if username in self._username_index:
            raise ValueError(f"Username '{username}' already taken")
        if email in self._email_index:
            raise ValueError(f"Email '{email}' already registered")

        user = User(username, email, name, bio, skills, interests)
        self.users[user.id] = user
        self._username_index[username] = user.id
        self._email_index[email] = user.id
        return user

    def get_user(self, user_id: str) -> Optional[User]:
        return self.users.get(user_id)

    def get_user_by_username(self, username: str) -> Optional[User]:
        uid = self._username_index.get(username)
        return self.users.get(uid) if uid else None

    def update_user(self, user_id: str, **kwargs) -> User:
        user = self.users.get(user_id)
        if not user:
            raise ValueError("User not found")
        if "email" in kwargs and kwargs["email"] != user.email:
            if kwargs["email"] in self._email_index:
                raise ValueError("Email already registered")
            del self._email_index[user.email]
            self._email_index[kwargs["email"]] = user_id
        user.update_profile(**kwargs)
        return user

    def delete_user(self, user_id: str) -> bool:
        user = self.users.get(user_id)
        if not user:
            return False
        del self._username_index[user.username]
        del self._email_index[user.email]
        del self.users[user_id]
        return True

    # --- Project Management ---

    def create_project(self, title: str, description: str, owner_id: str,
                       required_skills: Optional[List[str]] = None) -> Project:
        if owner_id not in self.users:
            raise ValueError("Owner user not found")
        project = Project(title, description, owner_id, required_skills)
        self.projects[project.id] = project
        return project

    def get_project(self, project_id: str) -> Optional[Project]:
        return self.projects.get(project_id)

    def add_member_to_project(self, project_id: str, user_id: str,
                              requester_id: str) -> bool:
        project = self.projects.get(project_id)
        if not project:
            raise ValueError("Project not found")
        if requester_id != project.owner_id:
            raise PermissionError("Only the project owner can add members")
        if user_id not in self.users:
            raise ValueError("User not found")
        return project.add_member(user_id)

    def remove_member_from_project(self, project_id: str, user_id: str,
                                   requester_id: str) -> bool:
        project = self.projects.get(project_id)
        if not project:
            raise ValueError("Project not found")
        if requester_id != project.owner_id:
            raise PermissionError("Only the project owner can remove members")
        return project.remove_member(user_id)

    # --- Search and Matching ---

    def search_users(self, query: str = "", skills: Optional[List[str]] = None,
                     interests: Optional[List[str]] = None) -> List[User]:
        results = []
        query_lower = query.lower()
        for user in self.users.values():
            match = True
            if query:
                text = f"{user.username} {user.name} {user.bio}".lower()
                if query_lower not in text:
                    match = False
            if skills and match:
                user_skills_lower = [s.lower() for s in user.skills]
                if not any(s.lower() in user_skills_lower for s in skills):
                    match = False
            if interests and match:
                user_interests_lower = [i.lower() for i in user.interests]
                if not any(i.lower() in user_interests_lower for i in interests):
                    match = False
            if match:
                results.append(user)
        return results

    def search_projects(self, query: str = "", skills: Optional[List[str]] = None,
                        status: str = "") -> List[Project]:
        results = []
        query_lower = query.lower()
        for project in self.projects.values():
            match = True
            if query:
                text = f"{project.title} {project.description}".lower()
                if query_lower not in text:
                    match = False
            if skills and match:
                proj_skills_lower = [s.lower() for s in project.required_skills]
                if not any(s.lower() in proj_skills_lower for s in skills):
                    match = False
            if status and match:
                if project.status != status:
                    match = False
            if match:
                results.append(project)
        return results

    def match_projects_for_user(self, user_id: str, limit: int = 10) -> List[Dict]:
        user = self.users.get(user_id)
        if not user:
            raise ValueError("User not found")

        scored_projects = []
        for project in self.projects.values():
            if user_id in project.members:
                continue
            if project.status != "active":
                continue

            score = 0.0
            user_skills_lower = {s.lower() for s in user.skills}
            req_skills_lower = {s.lower() for s in project.required_skills}

            # Skill match scoring
            if req_skills_lower:
                skill_overlap = user_skills_lower & req_skills_lower
                score += len(skill_overlap) / len(req_skills_lower) * 70

            # Interest match scoring
            user_interests_lower = {i.lower() for i in user.interests}
            project_text = f"{project.title} {project.description}".lower()
            for interest in user_interests_lower:
                if interest in project_text:
                    score += 10

            if score > 0:
                scored_projects.append({
                    "project": project,
                    "score": round(score, 2),
                    "matching_skills": list(user_skills_lower & req_skills_lower)
                })

        scored_projects.sort(key=lambda x: x["score"], reverse=True)
        return scored_projects[:limit]

    def match_users_for_project(self, project_id: str, limit: int = 10) -> List[Dict]:
        project = self.projects.get(project_id)
        if not project:
            raise ValueError("Project not found")

        scored_users = []
        req_skills_lower = {s.lower() for s in project.required_skills}

        for user in self.users.values():
            if user.id in project.members:
                continue

            score = 0.0
            user_skills_lower = {s.lower() for s in user.skills}

            if req_skills_lower:
                skill_overlap = user_skills_lower & req_skills_lower
                score += len(skill_overlap) / len(req_skills_lower) * 70

            user_interests_lower = {i.lower() for i in user.interests}
            project_text = f"{project.title} {project.description}".lower()
            for interest in user_interests_lower:
                if interest in project_text:
                    score += 10

            if score > 0:
                scored_users.append({
                    "user": user,
                    "score": round(score, 2),
                    "matching_skills": list(user_skills_lower & req_skills_lower)
                })

        scored_users.sort(key=lambda x: x["score"], reverse=True)
        return scored_users[:limit]

    # --- Messaging ---

    def send_message(self, project_id: str, channel_name: str,
                     sender_id: str, content: str) -> Message:
        project = self.projects.get(project_id)
        if not project:
            raise ValueError("Project not found")
        channel = None
        for ch in project.channels:
            if ch.name == channel_name:
                channel = ch
                break
        if not channel:
            raise ValueError(f"Channel '{channel_name}' not found")
        return channel.send_message(sender_id, content)

    def get_messages(self, project_id: str, channel_name: str,
                     limit: int = 50, offset: int = 0) -> List[Message]:
        project = self.projects.get(project_id)
        if not project:
            raise ValueError("Project not found")
        channel = None
        for ch in project.channels:
            if ch.name == channel_name:
                channel = ch
                break
        if not channel:
            raise ValueError(f"Channel '{channel_name}' not found")
        return channel.get_messages(limit, offset)

    # --- Code Repository ---

    def commit_code(self, project_id: str, author_id: str, message: str,
                    files_changed: Optional[List[str]] = None,
                    branch: str = "main") -> Commit:
        project = self.projects.get(project_id)
        if not project:
            raise ValueError("Project not found")
        if author_id not in project.members:
            raise PermissionError("User is not a project member")
        return project.repository.add_commit(author_id, message, files_changed, branch)

    def create_branch(self, project_id: str, branch_name: str,
                      from_branch: str = "main") -> bool:
        project = self.projects.get(project_id)
        if not project:
            raise ValueError("Project not found")
        return project.repository.create_branch(branch_name, from_branch)

    # --- Task Management ---

    def create_task(self, project_id: str, title: str, description: str = "",
                    assigned_to: Optional[str] = None) -> Task:
        project = self.projects.get(project_id)
        if not project:
            raise ValueError("Project not found")
        if assigned_to and assigned_to not in project.members:
            raise ValueError("Assigned user is not a project member")
        return project.add_task(title, description, assigned_to)

    def update_task_status(self, project_id: str, task_id: str, status: str) -> Task:
        project = self.projects.get(project_id)
        if not project:
            raise ValueError("Project not found")
        for task in project.tasks:
            if task.id == task_id:
                task.update_status(status)
                return task
        raise ValueError("Task not found")

    def get_task_board(self, project_id: str) -> Dict[str, List[Task]]:
        project = self.projects.get(project_id)
        if not project:
            raise ValueError("Project not found")
        return project.get_task_board()


