import unittest


class TestUserProfileCreation(unittest.TestCase):
    """Test user profile creation and management."""

    def setUp(self):
        self.app = CollaborateCraft()

    def test_create_user_valid(self):
        user = self.app.create_user("alice", "alice@example.com", "Alice Smith",
                                    skills=["Python", "JavaScript"])
        self.assertEqual(user.username, "alice")
        self.assertEqual(user.email, "alice@example.com")
        self.assertEqual(user.name, "Alice Smith")
        self.assertIn("Python", user.skills)

    def test_create_user_minimal(self):
        user = self.app.create_user("bob", "bob@test.org")
        self.assertEqual(user.username, "bob")
        self.assertEqual(user.skills, [])

    def test_create_user_invalid_email(self):
        with self.assertRaises(ValueError):
            self.app.create_user("charlie", "not-an-email")

    def test_create_user_empty_email(self):
        with self.assertRaises(ValueError):
            self.app.create_user("charlie", "")

    def test_create_user_invalid_username_empty(self):
        with self.assertRaises(ValueError):
            self.app.create_user("", "valid@email.com")

    def test_create_user_invalid_username_special_chars(self):
        with self.assertRaises(ValueError):
            self.app.create_user("user@name!", "valid@email.com")

    def test_create_user_duplicate_username(self):
        self.app.create_user("alice", "alice@example.com")
        with self.assertRaises(ValueError):
            self.app.create_user("alice", "another@example.com")

    def test_create_user_duplicate_email(self):
        self.app.create_user("alice", "alice@example.com")
        with self.assertRaises(ValueError):
            self.app.create_user("bob", "alice@example.com")

    def test_update_user_profile(self):
        user = self.app.create_user("alice", "alice@example.com")
        self.app.update_user(user.id, name="Alice Johnson", bio="Developer")
        self.assertEqual(user.name, "Alice Johnson")
        self.assertEqual(user.bio, "Developer")

    def test_update_user_email(self):
        user = self.app.create_user("alice", "alice@example.com")
        self.app.update_user(user.id, email="newalice@example.com")
        self.assertEqual(user.email, "newalice@example.com")

    def test_update_user_invalid_email(self):
        user = self.app.create_user("alice", "alice@example.com")
        with self.assertRaises(ValueError):
            self.app.update_user(user.id, email="bad-email")

    def test_update_user_bio_too_long(self):
        user = self.app.create_user("alice", "alice@example.com")
        with self.assertRaises(ValueError):
            self.app.update_user(user.id, bio="x" * 501)

    def test_add_remove_skills(self):
        user = self.app.create_user("alice", "alice@example.com")
        user.add_skill("Python")
        user.add_skill("Go")
        self.assertIn("Python", user.skills)
        self.assertIn("Go", user.skills)
        user.remove_skill("Python")
        self.assertNotIn("Python", user.skills)

    def test_add_duplicate_skill(self):
        user = self.app.create_user("alice", "alice@example.com")
        user.add_skill("Python")
        user.add_skill("Python")
        self.assertEqual(user.skills.count("Python"), 1)

    def test_add_remove_interests(self):
        user = self.app.create_user("alice", "alice@example.com")
        user.add_interest("machine learning")
        user.add_interest("web development")
        self.assertIn("machine learning", user.interests)
        user.remove_interest("machine learning")
        self.assertNotIn("machine learning", user.interests)

    def test_delete_user(self):
        user = self.app.create_user("alice", "alice@example.com")
        self.assertTrue(self.app.delete_user(user.id))
        self.assertIsNone(self.app.get_user(user.id))

    def test_delete_nonexistent_user(self):
        self.assertFalse(self.app.delete_user("nonexistent-id"))

    def test_get_user_by_username(self):
        user = self.app.create_user("alice", "alice@example.com")
        found = self.app.get_user_by_username("alice")
        self.assertEqual(found.id, user.id)

    def test_get_nonexistent_user_by_username(self):
